// Classify incoming artifact by file type and source
const input = $input.first().json;
const body = input.body || input;

const fileName = body.fileName || body.filename || body.name || '';
const source = body.source || body.platform || 'unknown';
const ext = fileName.split('.').pop().toLowerCase();

const typeMap = {
  'json': 'workflow',
  'md': 'document',
  'sql': 'migration',
  'py': 'script',
  'sh': 'script',
  'csv': 'data',
  'pdf': 'document',
  'png': 'screenshot',
  'jpg': 'screenshot',
  'jpeg': 'screenshot',
  'mp3': 'audio',
  'wav': 'audio',
  'm4a': 'audio'
};

const artifactType = typeMap[ext] || 'unknown';
const fareDestination = {
  'workflow': 'n8n-workflows/',
  'document': 'docs/',
  'migration': 'supabase/migrations/',
  'script': 'scripts/',
  'data': '03_Reference/',
  'screenshot': '06_Media/screenshots/',
  'audio': '06_Media/audio/',
  'unknown': '01_Inbox/'
};

return [{
  json: {
    ...body,
    fileName,
    extension: ext,
    artifactType,
    source,
    fareRoute: fareDestination[artifactType] || '01_Inbox/',
    classifiedAt: new Date().toISOString()
  }
}];

